class Solution:
    def hIndex(self, citations):
        n = len(citations)
        # Independent linear scan from the front: n - i papers have at least
        # citations[i] citations once sorted ascending.
        best = 0
        for i in range(n):
            h = min(citations[i], n - i)
            if h > best:
                best = h
        return best

